class Solution {
public:
    int maxScore(string s) {
        int maxScore = 0;
        int zeros = 0;
        for (int i = 0; i < s.length() - 1; i++) {
            if (s[i] == '0') zeros++;
            int ones = count(s.begin() + i + 1, s.end(), '1');
            maxScore = max(maxScore, zeros + ones);
        }
        return maxScore;
    }
};
